import React, { useState, useEffect } from 'react';
import api from '../services/authService';

interface ReporteReproductivo {
  servicios: Array<{ total: number; tipo: string; mes: string }>;
  partos: Array<{ total_partos: number; promedio_lechones: number; mes: string }>;
  tasa_paricion: { cerdas_servidas: number; partos_realizados: number };
}

interface ReporteMortalidad {
  mortalidad_categoria: Array<{ categoria: string; muertes: number; edad_promedio_dias: number }>;
  causas_principales: Array<{ motivo_salida: string; cantidad: number }>;
}

const Reports: React.FC = () => {
  const [activeTab, setActiveTab] = useState('reproductive');
  const [reporteReproductivo, setReporteReproductivo] = useState<ReporteReproductivo | null>(null);
  const [reporteMortalidad, setReporteMortalidad] = useState<ReporteMortalidad | null>(null);
  const [loading, setLoading] = useState(false);

  const [dateFilter, setDateFilter] = useState({
    fecha_inicio: new Date(new Date().getFullYear(), 0, 1).toISOString().split('T')[0],
    fecha_fin: new Date().toISOString().split('T')[0]
  });

  useEffect(() => {
    loadReports();
  }, [dateFilter, activeTab]);

  const loadReports = async () => {
    setLoading(true);
    try {
      if (activeTab === 'reproductive') {
        const response = await api.get(`/reports/reproductive?fecha_inicio=${dateFilter.fecha_inicio}&fecha_fin=${dateFilter.fecha_fin}`);
        setReporteReproductivo(response.data);
      } else if (activeTab === 'mortality') {
        const response = await api.get(`/reports/mortality?fecha_inicio=${dateFilter.fecha_inicio}&fecha_fin=${dateFilter.fecha_fin}`);
        setReporteMortalidad(response.data);
      }
    } catch (error) {
      console.error('Error cargando reportes:', error);
    } finally {
      setLoading(false);
    }
  };

  const exportToPDF = () => {
    alert('Funcionalidad de exportación PDF en desarrollo...');
  };

  const exportToExcel = () => {
    alert('Funcionalidad de exportación Excel en desarrollo...');
  };

  const tabStyle = (tab: string) => ({
    padding: '12px 24px',
    border: 'none',
    backgroundColor: activeTab === tab ? '#6f42c1' : '#f8f9fa',
    color: activeTab === tab ? 'white' : '#333',
    cursor: 'pointer',
    borderRadius: '4px 4px 0 0',
    marginRight: '2px'
  });

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-3">
        <h1>📊 Reportes y Análisis</h1>
        <div>
          <button 
            className="btn btn-danger"
            onClick={exportToPDF}
            style={{ marginRight: '10px' }}
          >
            📄 Exportar PDF
          </button>
          <button 
            className="btn btn-success"
            onClick={exportToExcel}
          >
            📊 Exportar Excel
          </button>
        </div>
      </div>

      {/* Filtro de fechas */}
      <div className="card mb-3">
        <div className="d-flex align-items-center" style={{ gap: '15px' }}>
          <label>Período del reporte:</label>
          <input
            type="date"
            className="form-control"
            style={{ width: 'auto' }}
            value={dateFilter.fecha_inicio}
            onChange={(e) => setDateFilter({...dateFilter, fecha_inicio: e.target.value})}
          />
          <span>hasta</span>
          <input
            type="date"
            className="form-control"
            style={{ width: 'auto' }}
            value={dateFilter.fecha_fin}
            onChange={(e) => setDateFilter({...dateFilter, fecha_fin: e.target.value})}
          />
        </div>
      </div>

      {/* Tabs */}
      <div style={{ marginBottom: '20px' }}>
        <button 
          style={tabStyle('reproductive')}
          onClick={() => setActiveTab('reproductive')}
        >
          🐷 Reproductivo
        </button>
        <button 
          style={tabStyle('mortality')}
          onClick={() => setActiveTab('mortality')}
        >
          ⚰️ Mortalidad
        </button>
        <button 
          style={tabStyle('growth')}
          onClick={() => setActiveTab('growth')}
        >
          📈 Crecimiento
        </button>
        <button 
          style={tabStyle('inventory')}
          onClick={() => setActiveTab('inventory')}
        >
          📦 Inventario
        </button>
      </div>

      {loading && (
        <div className="card">
          <div style={{ textAlign: 'center', padding: '40px' }}>
            <div style={{ fontSize: '48px', marginBottom: '15px' }}>⏳</div>
            <p>Generando reporte...</p>
          </div>
        </div>
      )}

      {/* Reporte Reproductivo */}
      {activeTab === 'reproductive' && reporteReproductivo && !loading && (
        <div>
          {/* KPIs Reproductivos */}
          <div className="grid grid-3 mb-3">
            <div className="card text-center">
              <h3 style={{ color: '#007bff', fontSize: '36px', marginBottom: '10px' }}>
                {reporteReproductivo.tasa_paricion.cerdas_servidas}
              </h3>
              <p style={{ color: '#7f8c8d', fontWeight: '500' }}>Cerdas Servidas</p>
            </div>
            <div className="card text-center">
              <h3 style={{ color: '#28a745', fontSize: '36px', marginBottom: '10px' }}>
                {reporteReproductivo.tasa_paricion.partos_realizados}
              </h3>
              <p style={{ color: '#7f8c8d', fontWeight: '500' }}>Partos Realizados</p>
            </div>
            <div className="card text-center">
              <h3 style={{ color: '#17a2b8', fontSize: '36px', marginBottom: '10px' }}>
                {reporteReproductivo.tasa_paricion.cerdas_servidas > 0 ? 
                  Math.round((reporteReproductivo.tasa_paricion.partos_realizados / reporteReproductivo.tasa_paricion.cerdas_servidas) * 100) : 0}%
              </h3>
              <p style={{ color: '#7f8c8d', fontWeight: '500' }}>Tasa de Parición</p>
            </div>
          </div>

          <div className="grid grid-2">
            {/* Servicios por tipo */}
            <div className="card">
              <h3>Servicios Realizados</h3>
              {reporteReproductivo.servicios.length > 0 ? (
                <table className="table">
                  <thead>
                    <tr>
                      <th>Mes</th>
                      <th>Tipo</th>
                      <th>Cantidad</th>
                    </tr>
                  </thead>
                  <tbody>
                    {reporteReproductivo.servicios.map((servicio, index) => (
                      <tr key={index}>
                        <td>{servicio.mes}</td>
                        <td style={{ textTransform: 'capitalize' }}>{servicio.tipo}</td>
                        <td>
                          <span style={{
                            padding: '4px 12px',
                            borderRadius: '20px',
                            backgroundColor: '#007bff',
                            color: 'white',
                            fontSize: '14px'
                          }}>
                            {servicio.total}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              ) : (
                <p style={{ textAlign: 'center', color: '#666', padding: '20px' }}>
                  No hay servicios en el período
                </p>
              )}
            </div>

            {/* Partos por mes */}
            <div className="card">
              <h3>Partos por Mes</h3>
              {reporteReproductivo.partos.length > 0 ? (
                <table className="table">
                  <thead>
                    <tr>
                      <th>Mes</th>
                      <th>Partos</th>
                      <th>Lechones/Parto</th>
                    </tr>
                  </thead>
                  <tbody>
                    {reporteReproductivo.partos.map((parto, index) => (
                      <tr key={index}>
                        <td>{parto.mes}</td>
                        <td>
                          <span style={{
                            padding: '4px 12px',
                            borderRadius: '20px',
                            backgroundColor: '#28a745',
                            color: 'white',
                            fontSize: '14px'
                          }}>
                            {parto.total_partos}
                          </span>
                        </td>
                        <td style={{ fontWeight: 'bold', color: '#17a2b8' }}>
                          {parseFloat(parto.promedio_lechones).toFixed(1)}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              ) : (
                <p style={{ textAlign: 'center', color: '#666', padding: '20px' }}>
                  No hay partos en el período
                </p>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Reporte de Mortalidad */}
      {activeTab === 'mortality' && reporteMortalidad && !loading && (
        <div className="grid grid-2">
          <div className="card">
            <h3>Mortalidad por Categoría</h3>
            {reporteMortalidad.mortalidad_categoria.length > 0 ? (
              <table className="table">
                <thead>
                  <tr>
                    <th>Categoría</th>
                    <th>Muertes</th>
                    <th>Edad Promedio</th>
                  </tr>
                </thead>
                <tbody>
                  {reporteMortalidad.mortalidad_categoria.map((item, index) => (
                    <tr key={index}>
                      <td style={{ textTransform: 'capitalize' }}>{item.categoria}</td>
                      <td>
                        <span style={{
                          padding: '4px 12px',
                          borderRadius: '20px',
                          backgroundColor: '#dc3545',
                          color: 'white',
                          fontSize: '14px'
                        }}>
                          {item.muertes}
                        </span>
                      </td>
                      <td>{Math.round(item.edad_promedio_dias)} días</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            ) : (
              <div style={{ textAlign: 'center', padding: '40px', color: '#28a745' }}>
                <div style={{ fontSize: '48px', marginBottom: '15px' }}>✅</div>
                <p>No hay mortalidad registrada en el período</p>
              </div>
            )}
          </div>

          <div className="card">
            <h3>Principales Causas</h3>
            {reporteMortalidad.causas_principales.length > 0 ? (
              <div>
                {reporteMortalidad.causas_principales.map((causa, index) => (
                  <div key={index} style={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    padding: '12px 0',
                    borderBottom: index < reporteMortalidad.causas_principales.length - 1 ? '1px solid #ecf0f1' : 'none'
                  }}>
                    <span style={{ fontWeight: '500' }}>
                      {causa.motivo_salida || 'No especificado'}
                    </span>
                    <span style={{
                      padding: '4px 12px',
                      borderRadius: '20px',
                      backgroundColor: '#ffc107',
                      color: '#212529',
                      fontSize: '14px',
                      fontWeight: 'bold'
                    }}>
                      {causa.cantidad}
                    </span>
                  </div>
                ))}
              </div>
            ) : (
              <div style={{ textAlign: 'center', padding: '40px', color: '#28a745' }}>
                <div style={{ fontSize: '48px', marginBottom: '15px' }}>✅</div>
                <p>No hay causas registradas</p>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Otros reportes en desarrollo */}
      {(activeTab === 'growth' || activeTab === 'inventory') && !loading && (
        <div className="card">
          <div style={{ textAlign: 'center', padding: '60px', color: '#666' }}>
            <div style={{ fontSize: '64px', marginBottom: '20px' }}>🚧</div>
            <h3 style={{ marginBottom: '15px' }}>Reporte en Desarrollo</h3>
            <p>Este reporte estará disponible en la próxima actualización del sistema.</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default Reports;
